  script: Int,
  region: Int,
  variant: Int,
): String? {
  if (region != 0 || script != 0 || variant != 0) {
    return null
  }
  return when (query) {
    139 -> "Ҳонконг" // HK
    193 -> "Макао" // MO
    229 -> "Фаластин" // PS
    297 -> "ИМ" // US
    else -> null
  }
}

